import React, { useState } from 'react';
import { Calendar, RefreshCw, FileSpreadsheet, Printer } from 'lucide-react';
import AdminNavigation from './AdminNavigation';
import api from '../../utils/api';
import * as XLSX from 'xlsx';

// ─── Logo data (base64) — embedded from official xlsx template ────────────────
const PAMPANGA_SEAL_B64   = 'data:image/png;base64,';
const OPA_LOGO_B64        = 'data:image/jpeg;base64,';
const BAGONG_PILIPINAS_B64= 'data:image/png;base64,';

// ─── Constants ────────────────────────────────────────────────────────────────
const MONTHS = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December'
];
const currentYear  = new Date().getFullYear();
const currentMonth = new Date().getMonth();
const YEARS = Array.from({ length: 5 }, (_, i) => currentYear - i);

function capitalize(str) {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1);
}

function severityToPct(severity) {
  const map = { low: 0.05, medium: 0.15, high: 0.30, critical: 0.50 };
  return map[severity] ?? null;
}

// ─── Load image as Uint8Array for xlsx ────────────────────────────────────────
async function loadImageBytes(dataUrl) {
  const res = await fetch(dataUrl);
  const buf = await res.arrayBuffer();
  return new Uint8Array(buf);
}

// ─── Excel export ─────────────────────────────────────────────────────────────
// Matches the EXACT layout of the provincial Pest Monitoring template:
//  Row 1  : [blank — logo row, tall]
//  Row 2  : Republic of the Philippines        (merged A:Q)
//  Row 3  : Province of Pampanga               (merged A:Q)
//  Row 4  : OFFICE OF THE PROVINCIAL AGRICULTURIST (merged A:Q)
//  Row 5  : Capitol Compound / Municipality    (merged A:Q)
//  Row 6  : [blank]
//  Row 7  : PEST MONITORING ON RICE...         (merged A:Q)
//  Row 8  : as of <date>                       (merged A:Q)
//  Row 9  : [blank]
//  Row 10 : [blank]
//  Row 11 : Municipality: MAGALANG, PAMPANGA   (merged A:Q)
//  Row 12 : Column headers (green fill, bold)
//  Row 13+: Data rows, sub-total rows, blank separators
//  ...    : Signatories

async function exportToExcel(detections, farms, month, year) {
  const endOfMonth = new Date(year, month + 1, 0).getDate();
  const sheetLabel = `${MONTHS[month].slice(0, 3)} ${endOfMonth}, ${year}`;
  const farmById   = Object.fromEntries(farms.map(f => [f.id, f]));

  // No grouping — treat all detections as a single list

  // ── Build array-of-arrays matching the exact template layout ─────────────
  // Template row structure (1-indexed, matching actual xlsx):
  //   Row 1  : blank (logos float here as images)
  //   Row 2  : Republic of the Philippines       (merged A:Q, Bookman Old Style 12)
  //   Row 3  : Province of Pampanga              (merged A:Q, Bookman Old Style 12)
  //   Row 4  : OFFICE OF THE PROVINCIAL AGRICULTURIST  (merged A:Q, Bookman Old Style 12)
  //   Row 5  : Capitol Compound, Sto. Niño, City of San Fernando  (merged A:Q, Bookman Old Style 12)
  //   Row 6  : blank
  //   Row 7  : PEST MONITORING ON RICE, CORN, CASSAVA & HIGH VALUE CROPS (merged A:Q, TNR 12 bold)
  //   Row 8  : as of <date>                      (merged A:Q, TNR 12 bold)
  //   Row 9  : blank
  //   Row 10 : blank
  //   Row 11 : Province: PAMPANGA                (TNR 12, no merge)
  //   Row 12 : Column headers                    (TNR 12 bold, green fill #92D050)
  //   Row 13+: Data rows, sub-total rows, blank separators

  const aoa = [];

  // Row 1 — blank (logos float here)
  aoa.push(Array(17).fill(null));

  // Rows 2–5 — letterhead (Bookman Old Style 12, centered)
  aoa.push(['Republic of the Philippines',              ...Array(16).fill(null)]);
  aoa.push(['Province of Pampanga',                    ...Array(16).fill(null)]);
  aoa.push(['OFFICE OF THE PROVINCIAL AGRICULTURIST',  ...Array(16).fill(null)]);
  aoa.push(['Capitol Compound, Sto. Niño, City of San Fernando', ...Array(16).fill(null)]);

  // Row 6 — blank
  aoa.push(Array(17).fill(null));

  // Row 7 — title
  aoa.push(['PEST MONITORING ON RICE AND CORN', ...Array(16).fill(null)]);

  // Row 8 — date
  aoa.push([`as of ${MONTHS[month]} ${endOfMonth}, ${year}`, ...Array(16).fill(null)]);

  // Rows 9–10 — blank
  aoa.push(Array(17).fill(null));
  aoa.push(Array(17).fill(null));

  // Row 11 — municipality label
  aoa.push(['Municipality: MAGALANG, PAMPANGA', ...Array(16).fill(null)]);

  // Row 12 — column headers
  aoa.push([
    'Municipality', 'Barangay', 'No.of Farmers Affected',
    'Latitude', 'Longitude', 'Crop', 'Variety', 'Growth Stage',
    'Pests', 'Natural Enemies Observed', 'Area Planted', 'Area Affected',
    '%infestation/infection', 'Area Treated', 'Actions Taken',
    'Data Source', 'Remarks',
  ]);

  // ── Data rows ─────────────────────────────────────────────────────────────
  // ── Flat data rows (no per-farm grouping) ────────────────────────────────
  const dataStartEx = aoa.length + 1; // Excel 1-indexed row of first data row

  detections.forEach(d => {
    const farm = farmById[d.farm_id] || null;
    const lat  = d.latitude  || (farm ? farm.lat  : null);
    const lng  = d.longitude || (farm ? farm.lng  : null);
    // Store as decimal — cell formatted as 0%
    const pct  = severityToPct(d.severity);
    aoa.push([
      'MAGALANG',                                        // A: Municipality
      (farm ? farm.barangay || null : null),             // B: Barangay — from farm
      null,                                              // C: No. of Farmers — blank
      lat ? Number(lat).toFixed(6) : null,               // D: Latitude
      lng ? Number(lng).toFixed(6) : null,               // E: Longitude
      capitalize(d.crop_type) || null,                   // F: Crop
      null,                                              // G: Variety — blank
      null,                                              // H: Growth Stage — blank
      d.pest_name || d.pest || null,                     // I: Pests
      null,                                              // J: Natural Enemies — blank
      null,                                              // K: Area Planted — blank
      null,                                              // L: Area Affected — blank
      pct,                                               // M: % Infestation (decimal, formatted 0%)
      null,                                              // N: Area Treated — blank
      null,                                              // O: Actions Taken — blank
      'PestCheck System',                                // P: Data Source
      d.confirmed ? 'Confirmed detection' : 'Unconfirmed', // Q: Remarks
    ]);
  });

  // Single grand total row (C, K, L sum entire data range)
  const dataEndEx = aoa.length;
  const totalRow  = Array(17).fill(null);
  totalRow[0]  = 'TOTAL';
  totalRow[2]  = `=SUM(C${dataStartEx}:C${dataEndEx})`;  // C
  totalRow[10] = `=SUM(K${dataStartEx}:K${dataEndEx})`;  // K
  totalRow[11] = `=SUM(L${dataStartEx}:L${dataEndEx})`;  // L
  aoa.push(totalRow);

  // Signatories (matching template rows 105–109)
  aoa.push(Array(17).fill(null));
  aoa.push(['* NOTHING FOLLOWS *', ...Array(16).fill(null)]);
  aoa.push(Array(17).fill(null));
  const prepRow = Array(17).fill(null);
  prepRow[0] = 'Prepared by:';
  prepRow[9] = 'Noted by:';
  aoa.push(prepRow);
  aoa.push(Array(17).fill(null));
  aoa.push(Array(17).fill(null));
  aoa.push(Array(17).fill(null));
  const nameRow = Array(17).fill(null);
  nameRow[1] = '________________________';
  nameRow[9] = '________________________';
  aoa.push(nameRow);
  const titleRow = Array(17).fill(null);
  titleRow[1] = 'Agricultural Technician';
  titleRow[9] = 'Municipal Agriculturist';
  aoa.push(titleRow);

  // ── Create worksheet ──────────────────────────────────────────────────────
  const ws = XLSX.utils.aoa_to_sheet(aoa);

  // ── Column widths — exact match to template ───────────────────────────────
  ws['!cols'] = [
    { wch: 24.0        }, // A  Municipality
    { wch: 23.6640625  }, // B  Barangay
    { wch: 15.6640625  }, // C  No. of Farmers
    { wch: 17.33203125 }, // D  Latitude
    { wch: 17.33203125 }, // E  Longitude
    { wch: 17.33203125 }, // F  Crop  (template has no explicit width for E/F — using D width)
    { wch: 15.5546875  }, // G  Variety
    { wch: 22.33203125 }, // H  Growth Stage
    { wch: 21.0        }, // I  Pests
    { wch: 11.44140625 }, // J  Natural Enemies
    { wch: 9.33203125  }, // K  Area Planted
    { wch: 11.33203125 }, // L  Area Affected
    { wch: 14.109375   }, // M  % Infestation
    { wch: 10.6640625  }, // N  Area Treated
    { wch: 10.6640625  }, // O  Actions Taken
    { wch: 10.0        }, // P  Data Source
    { wch: 12.5546875  }, // Q  Remarks
  ];

  // ── Row heights — only row 12 (headers) has a fixed height in the template ─
  ws['!rows'] = [];
  // aoa index 11 = Excel row 12 = header row
  ws['!rows'][11] = { hpt: 42.6 };

  // ── Merges — matching template exactly ───────────────────────────────────
  // aoa indices are 0-based; Excel rows are 1-based
  // Row 2  = aoa[1]  (Republic)
  // Row 3  = aoa[2]  (Province)
  // Row 4  = aoa[3]  (Office)
  // Row 5  = aoa[4]  (Address)
  // Row 7  = aoa[6]  (Title)
  // Row 8  = aoa[7]  (Date)
  ws['!merges'] = [
    { s: { r: 1, c: 0 }, e: { r: 1, c: 16 } },  // Row 2: Republic
    { s: { r: 2, c: 0 }, e: { r: 2, c: 16 } },  // Row 3: Province
    { s: { r: 3, c: 0 }, e: { r: 3, c: 16 } },  // Row 4: Office
    { s: { r: 4, c: 0 }, e: { r: 4, c: 16 } },  // Row 5: Address
    { s: { r: 6, c: 0 }, e: { r: 6, c: 16 } },  // Row 7: Title
    { s: { r: 7, c: 0 }, e: { r: 7, c: 16 } },  // Row 8: Date
  ];

  // ── Cell styles ───────────────────────────────────────────────────────────
  // Bookman Old Style 12 centered (letterhead rows 2–5)
  const LETTERHEAD_STYLE = {
    alignment: { horizontal: 'center', vertical: 'center' },
    font: { sz: 12, name: 'Bookman Old Style' },
  };
  // Times New Roman 12 bold centered (title / date rows 7–8)
  const TITLE_STYLE = {
    alignment: { horizontal: 'center', vertical: 'center' },
    font: { bold: true, sz: 12, name: 'Times New Roman' },
  };
  // Times New Roman 12 left (province label row 11)
  const PROVINCE_STYLE = {
    font: { sz: 12, name: 'Times New Roman' },
  };
  // Green header: Times New Roman 12 bold, green fill, centered, wrapped, medium border
  const GREEN_HDR = {
    fill: { patternType: 'solid', fgColor: { rgb: 'FF92D050' } },
    font: { bold: true, sz: 12, name: 'Times New Roman' },
    alignment: { horizontal: 'center', vertical: 'center', wrapText: true },
    border: {
      top:    { style: 'medium' },
      bottom: { style: 'medium' },
      left:   { style: 'medium' },
      right:  { style: 'medium' },
    },
  };
  // Data cell: Times New Roman 12, thin borders (left/right/bottom only — top=none)
  const DATA_STYLE = {
    font: { sz: 12, name: 'Times New Roman' },
    alignment: { vertical: 'center', wrapText: true },
    border: {
      left:   { style: 'thin' },
      right:  { style: 'thin' },
      bottom: { style: 'thin' },
    },
  };
  const DATA_CENTER = {
    ...DATA_STYLE,
    alignment: { horizontal: 'center', vertical: 'center', wrapText: true },
  };
  // % infestation cell — same as DATA_CENTER but with numFmt 0%
  const PCT_STYLE = {
    ...DATA_CENTER,
    numFmt: '0%',
  };
  // Sub-total cells: bold version of data
  const SUBTOTAL_STYLE = {
    font: { bold: true, sz: 12, name: 'Times New Roman' },
    alignment: { horizontal: 'center', vertical: 'center', wrapText: true },
    border: {
      left:   { style: 'thin' },
      right:  { style: 'thin' },
      bottom: { style: 'thin' },
    },
  };

  // Apply letterhead styles (Excel rows 2–5 = aoa indices 1–4)
  ['A2','A3','A4','A5'].forEach(addr => {
    if (ws[addr]) ws[addr].s = LETTERHEAD_STYLE;
  });

  // Apply title/date styles (Excel rows 7–8)
  ['A7','A8'].forEach(addr => {
    if (ws[addr]) ws[addr].s = TITLE_STYLE;
  });

  // Province label (Excel row 11)
  if (ws['A11']) ws['A11'].s = PROVINCE_STYLE;

  // Green header row (Excel row 12)
  'ABCDEFGHIJKLMNOPQ'.split('').forEach(col => {
    const addr = `${col}12`;
    if (!ws[addr]) ws[addr] = { t: 's', v: '' };
    ws[addr].s = GREEN_HDR;
  });

  // Apply styles to all data rows (Excel row 13 onward = aoa index 12 onward)
  const cols = 'ABCDEFGHIJKLMNOPQ'.split('');
  const totalExRow = aoa.length; // Excel row number of the grand total row
  for (let r = 13; r <= aoa.length; r++) {
    cols.forEach((col, ci) => {
      const addr = `${col}${r}`;
      if (!ws[addr]) return;
      if (col === 'M') {
        // % infestation — format as percentage
        ws[addr].s = PCT_STYLE;
        if (typeof ws[addr].v === 'number') ws[addr].t = 'n';
      } else if (col === 'C' || col === 'K' || col === 'L') {
        ws[addr].s = SUBTOTAL_STYLE;
      } else {
        ws[addr].s = col === 'B' || col === 'A' || col === 'I'
          ? DATA_STYLE
          : DATA_CENTER;
      }
    });
  }
  // Bold the TOTAL label cell
  const totalLabelAddr = `A${totalExRow}`;
  if (ws[totalLabelAddr]) {
    ws[totalLabelAddr].s = {
      ...DATA_STYLE,
      font: { bold: true, sz: 12, name: 'Times New Roman' },
      fill: { patternType: 'solid', fgColor: { rgb: 'FFE2EFDA' } },
    };
  }

  // ── Build workbook and generate bytes ─────────────────────────────────────
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, sheetLabel.slice(0, 31));

  // ── Set landscape print orientation ──────────────────────────────────────
  ws['!pageSetup'] = { orientation: 'landscape', paperSize: 9 }; // paperSize 9 = A4
  const wbBytes = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });

  // ── Inject logos via JSZip ────────────────────────────────────────────────
  // The template has 3 floating images positioned over the letterhead area.
  // We anchor them to rows 1–5 (0-indexed rows 0–4) matching the template layout:
  //   Left (col 0):   Bagong Pilipinas logo
  //   Center (col 7): Pampanga Provincial Seal
  //   Right (col 14): OPA Logo
  try {
    const { default: JSZip } = await import('https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js')
      .catch(() => { throw new Error('JSZip not available'); });

    const [sealBytes, opaBytes, bagongBytes] = await Promise.all([
      loadImageBytes(PAMPANGA_SEAL_B64),
      loadImageBytes(OPA_LOGO_B64),
      loadImageBytes(BAGONG_PILIPINAS_B64),
    ]);

    const zip = await JSZip.loadAsync(wbBytes);

    zip.file('xl/media/image1.jpeg', opaBytes);
    zip.file('xl/media/image2.png',  sealBytes);
    zip.file('xl/media/image3.png',  bagongBytes);

    // Drawing relationships
    const drawingRels = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image3.png"/>
  <Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image2.png"/>
  <Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image1.jpeg"/>
</Relationships>`;

    // Drawing XML — logos anchored over rows 1–5 (0-indexed rows 0–4)
    // Columns: A-B (0-1) = Bagong Pilipinas, H-I (7-8) = Pampanga Seal, O-P (14-15) = OPA Logo
    // EMU offsets keep images within the letterhead rows
    const drawingXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<xdr:wsDr xmlns:xdr="http://schemas.openxmlformats.org/drawingml/2006/spreadsheetDrawing" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">
  <xdr:twoCellAnchor moveWithCells="1" sizeWithCells="0">
    <xdr:from><xdr:col>0</xdr:col><xdr:colOff>76200</xdr:colOff><xdr:row>1</xdr:row><xdr:rowOff>76200</xdr:rowOff></xdr:from>
    <xdr:to><xdr:col>2</xdr:col><xdr:colOff>0</xdr:colOff><xdr:row>5</xdr:row><xdr:rowOff>0</xdr:rowOff></xdr:to>
    <xdr:pic>
      <xdr:nvPicPr>
        <xdr:cNvPr id="2" name="BagongPilipinas"/>
        <xdr:cNvPicPr><a:picLocks noChangeAspect="1"/></xdr:cNvPicPr>
      </xdr:nvPicPr>
      <xdr:blipFill>
        <a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId1"/>
        <a:stretch><a:fillRect/></a:stretch>
      </xdr:blipFill>
      <xdr:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="1000000" cy="1000000"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></xdr:spPr>
    </xdr:pic>
    <xdr:clientData/>
  </xdr:twoCellAnchor>
  <xdr:twoCellAnchor moveWithCells="1" sizeWithCells="0">
    <xdr:from><xdr:col>7</xdr:col><xdr:colOff>200000</xdr:colOff><xdr:row>1</xdr:row><xdr:rowOff>76200</xdr:rowOff></xdr:from>
    <xdr:to><xdr:col>9</xdr:col><xdr:colOff>200000</xdr:colOff><xdr:row>5</xdr:row><xdr:rowOff>0</xdr:rowOff></xdr:to>
    <xdr:pic>
      <xdr:nvPicPr>
        <xdr:cNvPr id="3" name="PampangaSeal"/>
        <xdr:cNvPicPr><a:picLocks noChangeAspect="1"/></xdr:cNvPicPr>
      </xdr:nvPicPr>
      <xdr:blipFill>
        <a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId2"/>
        <a:stretch><a:fillRect/></a:stretch>
      </xdr:blipFill>
      <xdr:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="1000000" cy="1000000"/></a:xfrm><a:prstGeom prst="ellipse"><a:avLst/></a:prstGeom><a:noFill/></xdr:spPr>
    </xdr:pic>
    <xdr:clientData/>
  </xdr:twoCellAnchor>
  <xdr:twoCellAnchor moveWithCells="1" sizeWithCells="0">
    <xdr:from><xdr:col>14</xdr:col><xdr:colOff>200000</xdr:colOff><xdr:row>1</xdr:row><xdr:rowOff>76200</xdr:rowOff></xdr:from>
    <xdr:to><xdr:col>16</xdr:col><xdr:colOff>500000</xdr:colOff><xdr:row>5</xdr:row><xdr:rowOff>0</xdr:rowOff></xdr:to>
    <xdr:pic>
      <xdr:nvPicPr>
        <xdr:cNvPr id="4" name="OPALogo" descr="opa-logoRICE"/>
        <xdr:cNvPicPr><a:picLocks noChangeAspect="1"/></xdr:cNvPicPr>
      </xdr:nvPicPr>
      <xdr:blipFill>
        <a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId3" cstate="print"/>
        <a:stretch><a:fillRect/></a:stretch>
      </xdr:blipFill>
      <xdr:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="1000000" cy="1000000"/></a:xfrm><a:prstGeom prst="ellipse"><a:avLst/></a:prstGeom><a:noFill/></xdr:spPr>
    </xdr:pic>
    <xdr:clientData/>
  </xdr:twoCellAnchor>
</xdr:wsDr>`;

    zip.file('xl/drawings/drawing1.xml', drawingXml);
    zip.file('xl/drawings/_rels/drawing1.xml.rels', drawingRels);

    // Sheet relationship — link drawing to sheet1
    const sheetRels = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawing1.xml"/>
</Relationships>`;
    zip.file('xl/worksheets/_rels/sheet1.xml.rels', sheetRels);

    // Update [Content_Types].xml
    const contentTypes = await zip.file('[Content_Types].xml').async('string');
    let updatedCT = contentTypes;
    const additions = [];
    if (!updatedCT.includes('drawing1.xml')) {
      additions.push('<Override PartName="/xl/drawings/drawing1.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/>');
    }
    if (!updatedCT.includes('image/jpeg') && !updatedCT.includes('Extension="jpeg"')) {
      additions.push('<Default Extension="jpeg" ContentType="image/jpeg"/>');
    }
    if (!updatedCT.includes('Extension="png"')) {
      additions.push('<Default Extension="png" ContentType="image/png"/>');
    }
    if (additions.length > 0) {
      updatedCT = updatedCT.replace('</Types>', additions.join('\n') + '\n</Types>');
      zip.file('[Content_Types].xml', updatedCT);
    }

    // Patch sheet1.xml to reference the drawing and set landscape orientation
    const sheet1Xml = await zip.file('xl/worksheets/sheet1.xml').async('string');
    let patched = sheet1Xml;
    if (!patched.includes('<drawing')) {
      patched = patched.replace(
        '</worksheet>',
        '<drawing r:id="rId1" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/></worksheet>'
      );
    }
    if (!patched.includes('<pageSetup')) {
      patched = patched.replace(
        '</worksheet>',
        '<pageSetup orientation="landscape" paperSize="9"/></worksheet>'
      );
    }
    zip.file('xl/worksheets/sheet1.xml', patched);

    const finalBytes = await zip.generateAsync({ type: 'arraybuffer' });
    const blob = new Blob([finalBytes], {
      type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    });
    triggerDownload(blob, `Pest_Monitoring_Report_${MONTHS[month]}_${year}.xlsx`);
  } catch (err) {
    console.warn('Image injection failed, downloading without logos:', err);
    const blob = new Blob([wbBytes], {
      type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    });
    triggerDownload(blob, `Pest_Monitoring_Report_${MONTHS[month]}_${year}.xlsx`);
  }
}

function triggerDownload(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a   = document.createElement('a');
  a.href     = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 5000);
}

// ─── Component ────────────────────────────────────────────────────────────────
const AdminMonthlyReport = ({ user, onLogout }) => {
  const [selectedMonth, setSelectedMonth] = useState(currentMonth);
  const [selectedYear,  setSelectedYear]  = useState(currentYear);
  const [detections,    setDetections]    = useState([]);
  const [farms,         setFarms]         = useState([]);
  const [loading,       setLoading]       = useState(false);
  const [generated,     setGenerated]     = useState(false);
  const [exporting,     setExporting]     = useState(false);

  // Editable row overrides: { [rowIndex]: { barangay, numFarmers, variety, growthStage, areaPlanted, areaAffected, areaTreated, naturalEnemies, actionsTaken } }
  const [rowEdits,      setRowEdits]      = useState({});
  const [editingRow,    setEditingRow]    = useState(null); // index of row being edited

  // Editable signature fields
  const [preparedBy,    setPreparedBy]    = useState('ALICIA C. DE LEON');
  const [preparedTitle, setPreparedTitle] = useState('Provincial Crop Protection Coordinator');
  const [notedBy,       setNotedBy]       = useState('JIMMY S. MANLICLIC');
  const [notedTitle,    setNotedTitle]    = useState('Assistant Provincial Agriculturist/ OIC - OPA');

  const updateRowEdit = (ri, field, value) => {
    setRowEdits(prev => ({
      ...prev,
      [ri]: { ...(prev[ri] || {}), [field]: value }
    }));
  };

  const fetchReportData = async () => {
    setLoading(true);
    setGenerated(false);
    try {
      const [detRes, farmRes] = await Promise.all([
        api.get('/admin/detections/?page_size=1000'),
        api.get('/admin/farms/'),
      ]);
      const allDet  = Array.isArray(detRes.data)  ? detRes.data  : (detRes.data.results  || []);
      const allFarm = Array.isArray(farmRes.data) ? farmRes.data : (farmRes.data.results || []);
      const filtered = allDet.filter(d => {
        const dt = new Date(d.detected_at || d.reported_at);
        return dt.getMonth() === selectedMonth && dt.getFullYear() === selectedYear;
      });
      setDetections(filtered);
      setFarms(allFarm);
      setGenerated(true);
    } catch (err) {
      console.error('Report fetch error:', err);
    } finally {
      setLoading(false);
    }
  };


  const handlePrint = () => {
    const reportEl = document.getElementById('printable-report');
    if (!reportEl) return;
    const html = `<!DOCTYPE html><html><head><meta charset="utf-8"/><title>Pest Monitoring Report</title><style>
@page{size:A4 landscape;margin:8mm;}
*{box-sizing:border-box;margin:0;padding:0;-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important;}
body{font-family:Arial,sans-serif;font-size:7pt;color:#000;background:#fff;-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important;}
.lh-wrap{display:flex;align-items:center;justify-content:center;gap:12px;padding:4px 8px;border-bottom:1px solid #ccc;}
.lh-logos img{height:48px;width:48px;object-fit:contain;}
.lh-text{text-align:center;padding:0 8px;}
.lh-text p{line-height:1.4;}
.lh-bold{font-weight:bold;font-size:8pt;}
.title-block{text-align:center;padding:4px 0;border-bottom:1px solid #ccc;}
.title-main{font-weight:bold;font-size:8pt;}
.title-sub{font-size:7pt;}
table{width:100%;border-collapse:collapse;table-layout:fixed;font-size:6.5pt;margin-top:4px;}
col.c1{width:9%;}col.c2{width:9%;}col.c3{width:4%;}col.c4{width:6%;}col.c5{width:6%;}
col.c6{width:5%;}col.c7{width:5%;}col.c8{width:7%;}col.c9{width:8%;}col.c10{width:6%;}
col.c11{width:5%;}col.c12{width:5%;}col.c13{width:5%;}col.c14{width:5%;}col.c15{width:6%;}
col.c16{width:6%;}col.c17{width:7%;}
th,td{border:0.5pt solid #aaa;padding:1.5pt 2pt;word-break:break-word;vertical-align:middle;}
thead tr{background-color:#92D050!important;font-weight:bold;text-align:center;}
thead th{background-color:#92D050!important;}
.subtotal{background-color:#E2EFDA!important;font-weight:bold;}
.subtotal td{background-color:#E2EFDA!important;}
.sep td{border:none;height:3pt;background:#f3f4f6!important;}
.tc{text-align:center;}.bold{font-weight:bold;}.muted{color:#aaa;}
.sig-wrap{display:flex;justify-content:space-between;padding:16px 16px 8px;}
.sig-col{width:42%;}
.sig-label{font-size:7pt;margin-bottom:24px;}
.sig-line{border-top:1pt solid #333;padding-top:2px;font-weight:bold;font-size:7pt;}
.sig-title{font-size:7pt;}
.nothing-follows{text-align:center;font-style:italic;font-size:7pt;color:#666;padding:8px 0;}
input.print-field,textarea.print-field{border:none!important;outline:none!important;background:transparent!important;font-size:inherit!important;font-family:inherit!important;color:inherit!important;font-weight:inherit!important;padding:0!important;margin:0!important;width:100%!important;resize:none!important;}
.sig-name-print{font-weight:bold;font-size:9pt;border-top:1pt solid #333;padding-top:2px;}
.sig-title-print{font-size:8pt;}
</style></head><body>${reportEl.innerHTML}</body></html>`;
    const iframe = document.createElement('iframe');
    iframe.style.cssText = 'position:fixed;top:-9999px;left:-9999px;width:0;height:0;border:none;';
    document.body.appendChild(iframe);
    iframe.contentDocument.open();
    iframe.contentDocument.write(html);
    iframe.contentDocument.close();
    iframe.contentWindow.focus();
    setTimeout(() => {
      iframe.contentWindow.print();
      setTimeout(() => document.body.removeChild(iframe), 1000);
    }, 500);
  };

  const handleExport = async () => {
    setExporting(true);
    try {
      await exportToExcel(detections, farms, selectedMonth, selectedYear);
    } finally {
      setExporting(false);
    }
  };

  // ── Derived ───────────────────────────────────────────────────────────────
  const farmById = Object.fromEntries(farms.map(f => [f.id, f]));

  const pestMap = detections.reduce((a, d) => {
    const p = d.pest_name || d.pest || 'Unknown'; a[p] = (a[p] || 0) + 1; return a;
  }, {});
  const sevMap = detections.reduce((a, d) => {
    const s = capitalize(d.severity || 'unknown'); a[s] = (a[s] || 0) + 1; return a;
  }, {});
  const cropMap = detections.reduce((a, d) => {
    const c = capitalize(d.crop_type) || 'Unknown'; a[c] = (a[c] || 0) + 1; return a;
  }, {});

  const endOfMonth = new Date(selectedYear, selectedMonth + 1, 0).getDate();

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <><div className="min-h-screen bg-gray-50">
        <div className="no-print"><AdminNavigation user={user} onLogout={onLogout} /></div>
        <div className="max-w-screen-2xl mx-auto px-6 py-6">

          {/* Page header */}
          <div className="flex flex-wrap items-center justify-between gap-4 mb-6 no-print">
            <div>
              <h1 className="text-2xl font-bold text-gray-800">Monthly Pest Monitoring Report</h1>
              <p className="text-sm text-gray-500 mt-0.5">
                Generate and export the official monthly pest monitoring report matching the provincial Excel template
              </p>
            </div>
            {generated && (
              <button
                onClick={handlePrint}
                className="flex items-center px-5 py-2.5 bg-blue-700 text-white rounded-lg hover:bg-blue-800 font-semibold text-sm shadow"
              >
                <Printer className="w-5 h-5 mr-2" />
                Print as PDF
              </button>
            )}
          </div>

          {/* Controls */}
          <div className="bg-white rounded-lg shadow p-5 mb-6 no-print">
            <div className="flex flex-wrap gap-4 items-end">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Month</label>
                <select
                  value={selectedMonth}
                  onChange={e => { setSelectedMonth(Number(e.target.value)); setGenerated(false); } }
                  className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500"
                >
                  {MONTHS.map((m, i) => <option key={m} value={i}>{m}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Year</label>
                <select
                  value={selectedYear}
                  onChange={e => { setSelectedYear(Number(e.target.value)); setGenerated(false); } }
                  className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500"
                >
                  {YEARS.map(y => <option key={y} value={y}>{y}</option>)}
                </select>
              </div>
              <button
                onClick={fetchReportData}
                disabled={loading}
                className="flex items-center px-5 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-400 text-sm font-medium"
              >
                {loading
                  ? <><RefreshCw className="w-4 h-4 mr-2 animate-spin" />Generating…</>
                  : <><Calendar className="w-4 h-4 mr-2" />Generate Report</>}
              </button>
            </div>
          </div>

          {generated && (
            <>
              {/* Summary cards */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6 no-print">
                {[
                  { label: 'Total Detections', value: detections.length, color: 'blue' },
                  { label: 'Confirmed', value: detections.filter(d => d.confirmed).length, color: 'green' },
                  { label: 'Pest Types', value: Object.keys(pestMap).length, color: 'purple' },
                  { label: 'Critical Cases', value: sevMap['Critical'] || 0, color: 'red' },
                ].map(({ label, value, color }) => (
                  <div key={label} className={`bg-white rounded-lg shadow p-4 border-l-4 border-${color}-500`}>
                    <p className="text-xs text-gray-500">{label}</p>
                    <p className={`text-2xl font-bold text-${color}-600`}>{value}</p>
                  </div>
                ))}
              </div>

              {/* Editing hint */}
              <div className="no-print mb-2 flex items-center gap-2 px-1 text-xs text-amber-700 bg-amber-50 border border-amber-200 rounded-lg py-2 px-3">
                <span>✏️</span>
                <span><strong>Click any row</strong> to edit blank fields (Barangay, Farmers, Variety, Growth Stage, Areas, Natural Enemies, Actions Taken). Edit <strong>Prepared by / Noted by</strong> names and titles directly in the signature section below.</span>
              </div>

              {/* ─── PRINTABLE REPORT — rendered in iframe for printing ──── */}
              <div id="printable-report" className="bg-white rounded-lg shadow mb-6" style={{ fontFamily: 'Arial, sans-serif' }}>

                {/* Letterhead — all logos flanking the center text */}
                <div className="lh-wrap" style={{ display:'flex', alignItems:'center', justifyContent:'center', padding:'8px 16px', borderBottom:'1px solid #ccc', gap:'12px' }}>
                  <img src={BAGONG_PILIPINAS_B64} alt="Bagong Pilipinas" style={{ height:'56px', width:'56px', objectFit:'contain', flexShrink:0 }} />
                  <div className="lh-text" style={{ textAlign:'center', padding:'0 8px' }}>
                    <p style={{ fontSize:'9pt' }}>Republic of the Philippines</p>
                    <p style={{ fontSize:'9pt' }}>Province of Pampanga</p>
                    <p className="lh-bold" style={{ fontWeight:'bold', fontSize:'10pt' }}>OFFICE OF THE PROVINCIAL AGRICULTURIST</p>
                    <p style={{ fontSize:'9pt' }}>Capitol Compound, Sto. Niño, City of San Fernando</p>
                  </div>
                  <img src={PAMPANGA_SEAL_B64} alt="Pampanga Seal" style={{ height:'56px', width:'56px', objectFit:'contain', flexShrink:0 }} />
                  <img src={OPA_LOGO_B64} alt="OPA Logo" style={{ height:'56px', width:'56px', objectFit:'contain', borderRadius:'50%', flexShrink:0 }} />
                </div>

                {/* Title block */}
                <div className="title-block" style={{ textAlign:'center', padding:'6px 0', borderBottom:'1px solid #ccc' }}>
                  <p className="title-main" style={{ fontWeight:'bold', fontSize:'10pt' }}>PEST MONITORING ON RICE AND CORN</p>
                  <p className="title-sub" style={{ fontSize:'9pt' }}>as of {MONTHS[selectedMonth]} {endOfMonth}, {selectedYear}</p>
                  <p className="title-sub" style={{ fontSize:'9pt', marginTop:'2px' }}>Province: <strong>PAMPANGA</strong></p>
                </div>

                {/* Table — uses only inline styles so iframe inherits correctly */}
                <div style={{ padding:'0 4px' }}>
                  <table style={{ width:'100%', borderCollapse:'collapse', tableLayout:'fixed', fontSize:'7pt' }}>
                    <colgroup>
                      <col className="c1"  style={{ width:'9%' }}  />
                      <col className="c2"  style={{ width:'9%' }}  />
                      <col className="c3"  style={{ width:'4%' }}  />
                      <col className="c4"  style={{ width:'6%' }}  />
                      <col className="c5"  style={{ width:'6%' }}  />
                      <col className="c6"  style={{ width:'5%' }}  />
                      <col className="c7"  style={{ width:'5%' }}  />
                      <col className="c8"  style={{ width:'7%' }}  />
                      <col className="c9"  style={{ width:'8%' }}  />
                      <col className="c10" style={{ width:'6%' }}  />
                      <col className="c11" style={{ width:'5%' }}  />
                      <col className="c12" style={{ width:'5%' }}  />
                      <col className="c13" style={{ width:'5%' }}  />
                      <col className="c14" style={{ width:'5%' }}  />
                      <col className="c15" style={{ width:'6%' }}  />
                      <col className="c16" style={{ width:'6%' }}  />
                      <col className="c17" style={{ width:'7%' }}  />
                    </colgroup>
                    <thead>
                      <tr style={{ backgroundColor:'#92D050', fontWeight:'bold', textAlign:'center' }}>
                        {[
                          'Municipality','Barangay','No. of\nFarmers','Lat','Lng',
                          'Crop','Variety','Growth\nStage','Pests','Natural\nEnemies',
                          'Area\nPlanted','Area\nAffected','%\nInfest.','Area\nTreated',
                          'Actions\nTaken','Data\nSource','Remarks'
                        ].map(h => (
                          <th key={h} style={{ border:'0.5pt solid #aaa', padding:'2pt 2pt', whiteSpace:'pre-line', fontWeight:'bold', textAlign:'center', verticalAlign:'middle', backgroundColor:'#92D050' }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {detections.length === 0 ? (
                        <tr>
                          <td colSpan={17} style={{ textAlign:'center', padding:'24pt', color:'#aaa', fontStyle:'italic', border:'0.5pt solid #aaa' }}>
                            No detections found for {MONTHS[selectedMonth]} {selectedYear}.
                          </td>
                        </tr>
                      ) : (
                        <>
                          {detections.map((d, ri) => {
                            const farm = farmById[d.farm_id] || null;
                            const lat  = d.latitude  || (farm ? farm.lat  : null);
                            const lng  = d.longitude || (farm ? farm.lng  : null);
                            const pct  = severityToPct(d.severity);
                            const pctColor = d.severity === 'critical' ? '#b91c1c'
                              : d.severity === 'high'   ? '#c2410c'
                              : d.severity === 'medium' ? '#ca8a04' : '#15803d';
                            const tdBase = { border:'0.5pt solid #aaa', padding:'1.5pt 2pt', verticalAlign:'middle', wordBreak:'break-word' };
                            const tdC    = { ...tdBase, textAlign:'center' };
                            const edits  = rowEdits[ri] || {};
                            const isEditing = editingRow === ri;

                            // Shared style for editable cells (screen only — print shows plain text)
                            const editableTdStyle = {
                              ...tdBase,
                              backgroundColor: isEditing ? '#fffbeb' : undefined,
                              position: 'relative',
                              cursor: 'pointer',
                            };
                            const editableTdCStyle = { ...editableTdStyle, textAlign:'center' };

                            const inputStyle = {
                              border: 'none', outline: 'none', background: 'transparent',
                              fontSize: 'inherit', fontFamily: 'inherit', color: 'inherit',
                              width: '100%', padding: 0, margin: 0, textAlign: 'inherit',
                            };

                            return (
                              <tr key={ri}
                                style={{ backgroundColor: ri % 2 === 0 ? '#fff' : '#f9fafb' }}
                                onClick={() => setEditingRow(isEditing ? null : ri)}
                                title="Click row to edit"
                              >
                                <td style={{ ...tdBase, fontWeight:'600' }}>Magalang</td>

                                {/* Barangay — editable */}
                                <td style={editableTdStyle} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={{ ...inputStyle }}
                                    placeholder={isEditing ? 'Barangay…' : '—'}
                                    value={edits.barangay ?? ''}
                                    onChange={e => updateRowEdit(ri, 'barangay', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                {/* No. of Farmers — editable */}
                                <td style={{ ...editableTdCStyle }} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={{ ...inputStyle, textAlign:'center' }}
                                    placeholder={isEditing ? '#' : '—'}
                                    value={edits.numFarmers ?? ''}
                                    onChange={e => updateRowEdit(ri, 'numFarmers', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                <td style={tdC}>{lat ? Number(lat).toFixed(6) : '—'}</td>
                                <td style={tdC}>{lng ? Number(lng).toFixed(6) : '—'}</td>
                                <td style={tdBase}>{capitalize(d.crop_type) || '—'}</td>

                                {/* Variety — editable */}
                                <td style={editableTdStyle} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={inputStyle}
                                    placeholder={isEditing ? 'Variety…' : '—'}
                                    value={edits.variety ?? ''}
                                    onChange={e => updateRowEdit(ri, 'variety', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                {/* Growth Stage — editable */}
                                <td style={editableTdStyle} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={inputStyle}
                                    placeholder={isEditing ? 'Stage…' : '—'}
                                    value={edits.growthStage ?? ''}
                                    onChange={e => updateRowEdit(ri, 'growthStage', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                <td style={{ ...tdBase, fontWeight:'500', color:'#b91c1c' }}>{d.pest_name || d.pest || '—'}</td>

                                {/* Natural Enemies — editable */}
                                <td style={editableTdStyle} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={inputStyle}
                                    placeholder={isEditing ? 'Enemies…' : '—'}
                                    value={edits.naturalEnemies ?? ''}
                                    onChange={e => updateRowEdit(ri, 'naturalEnemies', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                {/* Area Planted — editable */}
                                <td style={{ ...editableTdCStyle }} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={{ ...inputStyle, textAlign:'center' }}
                                    placeholder={isEditing ? 'ha' : '—'}
                                    value={edits.areaPlanted ?? ''}
                                    onChange={e => updateRowEdit(ri, 'areaPlanted', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                {/* Area Affected — editable */}
                                <td style={{ ...editableTdCStyle }} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={{ ...inputStyle, textAlign:'center' }}
                                    placeholder={isEditing ? 'ha' : '—'}
                                    value={edits.areaAffected ?? ''}
                                    onChange={e => updateRowEdit(ri, 'areaAffected', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                <td style={{ ...tdC, color: pctColor, fontWeight:'600' }}>{pct !== null ? `${(pct * 100).toFixed(0)}%` : '—'}</td>

                                {/* Area Treated — editable */}
                                <td style={{ ...editableTdCStyle }} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={{ ...inputStyle, textAlign:'center' }}
                                    placeholder={isEditing ? 'ha' : '—'}
                                    value={edits.areaTreated ?? ''}
                                    onChange={e => updateRowEdit(ri, 'areaTreated', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                {/* Actions Taken — editable */}
                                <td style={editableTdStyle} onClick={e => e.stopPropagation()}>
                                  <input
                                    className="print-field"
                                    style={inputStyle}
                                    placeholder={isEditing ? 'Actions…' : '—'}
                                    value={edits.actionsTaken ?? ''}
                                    onChange={e => updateRowEdit(ri, 'actionsTaken', e.target.value)}
                                    onClick={() => setEditingRow(ri)}
                                  />
                                </td>

                                <td style={{ ...tdC, color:'#6b7280' }}>PestCheck</td>
                                <td style={{ ...tdBase, color:'#6b7280' }}>{d.confirmed ? 'Confirmed' : 'Unconfirmed'}</td>
                              </tr>
                            );
                          })}
                          {/* Grand total row */}
                          <tr className="subtotal" style={{ backgroundColor:'#E2EFDA' }}>
                            <td colSpan={2} style={{ border:'0.5pt solid #aaa', padding:'1.5pt 2pt', fontWeight:'bold', fontSize:'7pt' }}>TOTAL</td>
                            <td style={{ border:'0.5pt solid #aaa', padding:'1.5pt 2pt', textAlign:'center', fontStyle:'italic', color:'#6b7280' }}>Σ {detections.length}</td>
                            <td colSpan={14} style={{ border:'0.5pt solid #aaa', padding:'1.5pt 2pt' }}></td>
                          </tr>
                        </>
                      )}
                    </tbody>
                  </table>
                </div>

                {/* Signature section */}
                <div className="sig-wrap" style={{ display:'flex', justifyContent:'space-between', padding:'20px 16px 12px' }}>
                  {/* Prepared By */}
                  <div style={{ width:'42%' }}>
                    <p className="sig-label" style={{ marginBottom:'32px', fontSize:'9pt' }}>Prepared by:</p>
                    <div style={{ borderTop:'1pt solid #333', paddingTop:'4px' }}>
                      <input
                        className="print-field"
                        style={{
                          fontWeight:'bold', fontSize:'9pt', border:'none', outline:'none',
                          background:'transparent', width:'100%', padding:0,
                          borderBottom:'1px dashed #aaa', marginBottom:'4px',
                        }}
                        value={preparedBy}
                        onChange={e => setPreparedBy(e.target.value)}
                        placeholder="Name (Prepared By)"
                      />
                      <input
                        className="print-field"
                        style={{
                          fontSize:'8pt', border:'none', outline:'none',
                          background:'transparent', width:'100%', padding:0,
                          borderBottom:'1px dashed #aaa',
                        }}
                        value={preparedTitle}
                        onChange={e => setPreparedTitle(e.target.value)}
                        placeholder="Title / Designation"
                      />
                    </div>
                  </div>
                  {/* Noted By */}
                  <div style={{ width:'42%' }}>
                    <p className="sig-label" style={{ marginBottom:'32px', fontSize:'9pt' }}>Noted by:</p>
                    <div style={{ borderTop:'1pt solid #333', paddingTop:'4px' }}>
                      <input
                        className="print-field"
                        style={{
                          fontWeight:'bold', fontSize:'9pt', border:'none', outline:'none',
                          background:'transparent', width:'100%', padding:0,
                          borderBottom:'1px dashed #aaa', marginBottom:'4px',
                        }}
                        value={notedBy}
                        onChange={e => setNotedBy(e.target.value)}
                        placeholder="Name (Noted By)"
                      />
                      <input
                        className="print-field"
                        style={{
                          fontSize:'8pt', border:'none', outline:'none',
                          background:'transparent', width:'100%', padding:0,
                          borderBottom:'1px dashed #aaa',
                        }}
                        value={notedTitle}
                        onChange={e => setNotedTitle(e.target.value)}
                        placeholder="Title / Designation"
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* Summary breakdowns — screen only */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
                <div className="bg-white rounded-lg shadow p-4">
                  <h3 className="text-sm font-bold text-gray-700 border-b pb-2 mb-3">By Crop Type</h3>
                  <table className="w-full text-xs">
                    <thead><tr className="text-gray-400"><th className="text-left pb-1">Crop</th><th className="text-right pb-1">#</th></tr></thead>
                    <tbody>
                      {Object.entries(cropMap).sort((a, b) => b[1] - a[1]).map(([c, n]) => (
                        <tr key={c} className="border-t border-gray-100">
                          <td className="py-1">{c}</td><td className="py-1 text-right font-semibold">{n}</td>
                        </tr>
                      ))}
                      <tr className="border-t-2 border-gray-300 font-bold">
                        <td className="pt-1">TOTAL</td><td className="pt-1 text-right">{detections.length}</td>
                      </tr>
                    </tbody>
                  </table>
                </div>
                <div className="bg-white rounded-lg shadow p-4">
                  <h3 className="text-sm font-bold text-gray-700 border-b pb-2 mb-3">Top Pest Incidences</h3>
                  <table className="w-full text-xs">
                    <thead><tr className="text-gray-400"><th className="text-left pb-1">Pest</th><th className="text-right pb-1">#</th></tr></thead>
                    <tbody>
                      {Object.entries(pestMap).sort((a, b) => b[1] - a[1]).slice(0, 8).map(([p, n]) => (
                        <tr key={p} className="border-t border-gray-100">
                          <td className="py-1">{p}</td><td className="py-1 text-right font-semibold">{n}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                <div className="bg-white rounded-lg shadow p-4">
                  <h3 className="text-sm font-bold text-gray-700 border-b pb-2 mb-3">Severity Distribution</h3>
                  <table className="w-full text-xs">
                    <thead><tr className="text-gray-400"><th className="text-left pb-1">Severity</th><th className="text-right pb-1">#</th></tr></thead>
                    <tbody>
                      {['Low', 'Medium', 'High', 'Critical'].map(s => (
                        <tr key={s} className="border-t border-gray-100">
                          <td className={`py-1 font-medium ${s === 'Critical' ? 'text-red-700' : s === 'High' ? 'text-orange-600' : s === 'Medium' ? 'text-yellow-600' : 'text-green-600'}`}>{s}</td>
                          <td className="py-1 text-right font-semibold">{sevMap[s] || 0}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Export CTA */}
              <div className="bg-green-50 border border-green-200 rounded-lg p-5 flex flex-wrap items-center justify-between gap-4">
                <div>
                  <p className="font-semibold text-green-800">Report ready to print</p>
                  <p className="text-sm text-green-700 mt-0.5">
                    Click <strong>Print as PDF</strong> to open the browser print dialog. Select <strong>Save as PDF</strong> as the destination for a digital copy.
                  </p>
                  <p className="text-xs text-green-600 mt-1">
                    Province pre-filled as <strong>PAMPANGA</strong>. Fill in any remaining blank fields directly in the table above before printing.
                  </p>
                </div>
                <button
                  onClick={handlePrint}
                  className="flex items-center px-5 py-3 bg-blue-700 text-white rounded-lg hover:bg-blue-800 font-semibold text-sm shadow"
                >
                  <Printer className="w-5 h-5 mr-2" />
                  Print as PDF
                </button>
              </div>
            </>
          )}

          {/* Empty state */}
          {!generated && !loading && (
            <div className="text-center py-24 text-gray-400">
              <FileSpreadsheet className="w-16 h-16 mx-auto mb-4 opacity-30" />
              <p className="text-lg">
                Select a month and year, then click{' '}
                <strong className="text-gray-600">Generate Report</strong>.
              </p>
            </div>
          )}
        </div>
      </div></>
  );
};

export default AdminMonthlyReport;